   282→// VectorMatchCardinality describes the cardinality relationship
   283→// of two Vectors in a binary operation.
   284→type VectorMatchCardinality int
   285→
   286→const (
   287→	CardOneToOne VectorMatchCardinality = iota
   288→	CardManyToOne
   289→	CardOneToMany
   290→	CardManyToMany
   291→)
   292→
   293→func (vmc VectorMatchCardinality) String() string {
   294→	switch vmc {
   295→	case CardOneToOne:
   296→		return "one-to-one"
   297→	case CardManyToOne:
   298→		return "many-to-one"
   299→	case CardOneToMany:
   300→		return "one-to-many"
   301→	case CardManyToMany:
   302→		return "many-to-many"
   303→	}
   304→	panic("promql.VectorMatchCardinality.String: unknown match cardinality")
   305→}
   306→
   307→// VectorMatching describes how elements from two Vectors in a binary
   308→// operation are supposed to be matched.
   309→type VectorMatching struct {
   310→	// The cardinality of the two Vectors.
   311→	Card VectorMatchCardinality
   312→	// MatchingLabels contains the labels which define equality of a pair of
   313→	// elements from the Vectors.
   314→	MatchingLabels []string
   315→	// On includes the given label names from matching,
   316→	// rather than excluding them.
   317→	On bool
   318→	// Include contains additional labels that should be included in
   319→	// the result from the side with the lower cardinality.
   320→	Include []string
   321→	// Fill-in values to use when a series from one side does not find a match on the other side.
   322→	FillValues VectorMatchFillValues
   323→}
   324→
   325→// VectorMatchFillValues contains the fill values to use for Vector matching
   326→// when one side does not find a match on the other side.
   327→// When a fill value is nil, no fill is applied for that side, and there
   328→// is no output for the match group if there is no match.
   329→type VectorMatchFillValues struct {
   330→	// RHS is the fill value to use for the right-hand side.
   331→	RHS *float64
   332→	// LHS is the fill value to use for the left-hand side.
   333→	LHS *float64
   334→}
