   336→// Visitor allows visiting a Node and its child nodes. The Visit method is
   337→// invoked for each node with the path leading to the node provided additionally.
   338→// If the result visitor w is not nil and no error, Walk visits each of the children
   339→// of node with the visitor w, followed by a call of w.Visit(nil, nil).
   340→type Visitor interface {
   341→	Visit(node Node, path []Node) (w Visitor, err error)
   342→}
   343→
   344→// Walk traverses an AST in depth-first order: It starts by calling
   345→// v.Visit(node, path); node must not be nil. If the visitor w returned by
   346→// v.Visit(node, path) is not nil and the visitor returns no error, Walk is
   347→// invoked recursively with visitor w for each of the non-nil children of node,
   348→// followed by a call of w.Visit(nil), returning an error
   349→// As the tree is descended the path of previous nodes is provided.
   350→func Walk(v Visitor, node Node, path []Node) error {
   351→	var err error
   352→	if v, err = v.Visit(node, path); v == nil || err != nil {
   353→		return err
   354→	}
   355→	var pathToHere []Node // Initialized only when needed.
   356→
   357→	for e := range ChildrenIter(node) {
   358→		if pathToHere == nil {
   359→			pathToHere = append(path, node)
   360→		}
   361→		if err := Walk(v, e, pathToHere); err != nil {
   362→			return err
   363→		}
   364→	}
   365→
   366→	_, err = v.Visit(nil, nil)
   367→	return err
   368→}
   369→
   370→func ExtractSelectors(expr Expr) [][]*labels.Matcher {
   371→	var selectors [][]*labels.Matcher
   372→	Inspect(expr, func(node Node, _ []Node) error {
   373→		vs, ok := node.(*VectorSelector)
   374→		if ok {
   375→			selectors = append(selectors, vs.LabelMatchers)
   376→		}
   377→		return nil
   378→	})
   379→	return selectors
   380→}
   381→
   382→type inspector func(Node, []Node) error
   383→
   384→func (f inspector) Visit(node Node, path []Node) (Visitor, error) {
   385→	if err := f(node, path); err != nil {
   386→		return nil, err
   387→	}
   388→
   389→	return f, nil
   390→}
   391→
   392→// Inspect traverses an AST in depth-first order: It starts by calling
   393→// f(node, path); node must not be nil. If f returns a nil error, Inspect invokes f
   394→// for all the non-nil children of node, recursively.
   395→// Note: path may be overwritten after f returns; copy path if you need to retain it.
   396→func Inspect(node Node, f inspector) {
   397→	var pathBuf [4]Node        // To reduce allocations during recursion.
   398→	Walk(f, node, pathBuf[:0]) //nolint:errcheck
   399→}
   400→
   401→// ChildrenIter returns an iterator over all child nodes of a syntax tree node.
   402→func ChildrenIter(node Node) func(func(Node) bool) {
   403→	return func(yield func(Node) bool) {
   404→		// According to lore, these switches have significantly better performance than interfaces
   405→		switch n := node.(type) {
   406→		case *EvalStmt:
   407→			yield(n.Expr)
   408→		case Expressions:
   409→			for _, e := range n {
   410→				if !yield(e) {
   411→					return
   412→				}
   413→			}
   414→		case *AggregateExpr:
   415→			if n.Expr != nil {
   416→				if !yield(n.Expr) {
   417→					return
   418→				}
   419→			}
   420→			if n.Param != nil {
   421→				yield(n.Param)
   422→			}
   423→		case *BinaryExpr:
   424→			if !yield(n.LHS) {
   425→				return
   426→			}
   427→			yield(n.RHS)
   428→		case *Call:
   429→			for _, e := range n.Args {
   430→				if !yield(e) {
   431→					return
   432→				}
   433→			}
   434→		case *SubqueryExpr:
   435→			yield(n.Expr)
   436→		case *ParenExpr:
   437→			yield(n.Expr)
   438→		case *UnaryExpr:
   439→			yield(n.Expr)
   440→		case *MatrixSelector:
   441→			yield(n.VectorSelector)
   442→		case *StepInvariantExpr:
   443→			yield(n.Expr)
   444→		case *NumberLiteral, *StringLiteral, *VectorSelector:
   445→			// nothing to do
   446→		default:
   447→			panic(fmt.Errorf("promql.ChildrenIter: unhandled node type %T", node))
   448→		}
   449→	}
   450→}
   451→
   452→// Children returns a list of all child nodes of a syntax tree node.
   453→// Implemented for backwards-compatibility; prefer ChildrenIter().
   454→func Children(node Node) []Node {
   455→	ret := []Node{}
   456→	for e := range ChildrenIter(node) {
   457→		ret = append(ret, e)
   458→	}
   459→	return ret
   460→}
