   462→// mergeRanges is a helper function to merge the PositionRanges of two Nodes.
   463→// Note that the arguments must be in the same order as they
   464→// occur in the input string.
   465→func mergeRanges(first, last Node) posrange.PositionRange {
   466→	return posrange.PositionRange{
   467→		Start: first.PositionRange().Start,
   468→		End:   last.PositionRange().End,
   469→	}
   470→}
   471→
   472→// PositionRange implements the Node interface.
   473→// This makes it possible to call mergeRanges on them.
   474→func (i *Item) PositionRange() posrange.PositionRange {
   475→	return posrange.PositionRange{
   476→		Start: i.Pos,
   477→		End:   i.Pos + posrange.Pos(len(i.Val)),
   478→	}
   479→}
   480→
   481→func (e *AggregateExpr) PositionRange() posrange.PositionRange {
   482→	return e.PosRange
   483→}
   484→
   485→func (e *BinaryExpr) PositionRange() posrange.PositionRange {
   486→	return mergeRanges(e.LHS, e.RHS)
   487→}
   488→
   489→func (e *DurationExpr) PositionRange() posrange.PositionRange {
   490→	if e.Op == STEP || e.Op == RANGE {
   491→		return posrange.PositionRange{
   492→			Start: e.StartPos,
   493→			End:   e.EndPos,
   494→		}
   495→	}
   496→	if e.RHS == nil {
   497→		return posrange.PositionRange{
   498→			Start: e.StartPos,
   499→			End:   e.RHS.PositionRange().End,
   500→		}
   501→	}
   502→	if e.LHS == nil {
   503→		return posrange.PositionRange{
   504→			Start: e.StartPos,
   505→			End:   e.RHS.PositionRange().End,
   506→		}
   507→	}
   508→	return mergeRanges(e.LHS, e.RHS)
   509→}
   510→
   511→func (e *Call) PositionRange() posrange.PositionRange {
   512→	return e.PosRange
   513→}
   514→
   515→func (e *EvalStmt) PositionRange() posrange.PositionRange {
   516→	return e.Expr.PositionRange()
   517→}
   518→
   519→func (e Expressions) PositionRange() posrange.PositionRange {
   520→	if len(e) == 0 {
   521→		// Position undefined.
   522→		return posrange.PositionRange{
   523→			Start: -1,
   524→			End:   -1,
   525→		}
   526→	}
   527→	return mergeRanges(e[0], e[len(e)-1])
   528→}
