   110→func (pql *promQLParser) ParseMetricSelectors(matchers []string) ([][]*labels.Matcher, error) {
   111→	var matcherSets [][]*labels.Matcher
   112→	for _, s := range matchers {
   113→		ms, err := pql.ParseMetricSelector(s)
   114→		if err != nil {
   115→			return nil, err
   116→		}
   117→		matcherSets = append(matcherSets, ms)
   118→	}
   119→	return matcherSets, nil
