   196→func (p *parser) parseExpr() (expr Expr, err error) {
   197→	defer p.recover(&err)
   198→
   199→	parseResult := p.parseGenerated(START_EXPRESSION)
   200→
   201→	if parseResult != nil {
   202→		expr = parseResult.(Expr)
   203→	}
   204→
   205→	// Only typecheck when there are no syntax errors.
   206→	if len(p.parseErrors) == 0 {
   207→		p.checkAST(expr)
   208→	}
   209→
   210→	if len(p.parseErrors) != 0 {
   211→		err = p.parseErrors
   212→	}
   213→
   214→	return expr, err
   215→}
