   313→// unexpected creates a parser error complaining about an unexpected lexer item.
   314→// The item that is presented as unexpected is always the last item produced
   315→// by the lexer.
   316→func (p *parser) unexpected(context, expected string) {
   317→	var errMsg strings.Builder
   318→
   319→	// Do not report lexer errors twice
   320→	if p.yyParser.lval.item.Typ == ERROR {
   321→		return
   322→	}
   323→
   324→	errMsg.WriteString("unexpected ")
   325→	errMsg.WriteString(p.yyParser.lval.item.desc())
   326→
   327→	if context != "" {
   328→		errMsg.WriteString(" in ")
   329→		errMsg.WriteString(context)
   330→	}
   331→
   332→	if expected != "" {
   333→		errMsg.WriteString(", expected ")
   334→		errMsg.WriteString(expected)
   335→	}
   336→
   337→	p.addParseErr(p.yyParser.lval.item.PositionRange(), errors.New(errMsg.String()))
   338→}
   339→
   340→var errUnexpected = errors.New("unexpected error")
   341→
   342→// recover is the handler that turns panics into returns from the top level of Parse.
   343→func (*parser) recover(errp *error) {
   344→	e := recover()
   345→	switch _, ok := e.(runtime.Error); {
   346→	case ok:
   347→		// Print the stack trace but do not inhibit the running application.
   348→		buf := make([]byte, 64<<10)
   349→		buf = buf[:runtime.Stack(buf, false)]
   350→
   351→		fmt.Fprintf(os.Stderr, "parser panic: %v\n%s", e, buf)
   352→		*errp = errUnexpected
   353→	case e != nil:
   354→		*errp = e.(error)
   355→	}
   356→}
   357→
   358→// Lex is expected by the yyLexer interface of the yacc generated parser.
   359→// It writes the next Item provided by the lexer to the provided pointer address.
   360→// Comments are skipped.
   361→//
   362→// The yyLexer interface is currently implemented by the parser to allow
   363→// the generated and non-generated parts to work together with regards to lookahead
   364→// and error handling.
   365→//
   366→// For more information, see https://pkg.go.dev/golang.org/x/tools/cmd/goyacc.
   367→func (p *parser) Lex(lval *yySymType) int {
   368→	var typ ItemType
   369→
   370→	if p.injecting {
   371→		p.injecting = false
   372→		return int(p.inject)
   373→	}
   374→	// Skip comments.
   375→	for {
   376→		p.lex.NextItem(&lval.item)
   377→		typ = lval.item.Typ
   378→		if typ != COMMENT {
   379→			break
   380→		}
   381→	}
   382→
   383→	switch typ {
   384→	case ERROR:
   385→		pos := posrange.PositionRange{
   386→			Start: p.lex.start,
   387→			End:   posrange.Pos(len(p.lex.input)),
   388→		}
   389→		p.addParseErr(pos, errors.New(p.yyParser.lval.item.Val))
   390→
   391→		// Tells yacc that this is the end of input.
   392→		return 0
   393→	case EOF:
   394→		lval.item.Typ = EOF
   395→		p.InjectItem(0)
   396→	case RIGHT_BRACE, RIGHT_PAREN, RIGHT_BRACKET, DURATION, NUMBER:
   397→		p.lastClosing = lval.item.Pos + posrange.Pos(len(lval.item.Val))
   398→	}
   399→
   400→	return int(typ)
   401→}
   402→
   403→// Error is expected by the yyLexer interface of the yacc generated parser.
   404→//
   405→// It is a no-op since the parsers error routines are triggered
   406→// by mechanisms that allow more fine-grained control
   407→// For more information, see https://pkg.go.dev/golang.org/x/tools/cmd/goyacc.
   408→func (*parser) Error(string) {
   409→}
   410→
   411→// InjectItem allows injecting a single Item at the beginning of the token stream
   412→// consumed by the generated parser.
   413→// This allows having multiple start symbols as described in
   414→// https://www.gnu.org/software/bison/manual/html_node/Multiple-start_002dsymbols.html .
   415→// Only the Lex function used by the generated parser is affected by this injected Item.
   416→// Trying to inject when a previously injected Item has not yet been consumed will panic.
   417→// Only Item types that are supposed to be used as start symbols are allowed as an argument.
   418→func (p *parser) InjectItem(typ ItemType) {
   419→	if p.injecting {
   420→		panic("cannot inject multiple Items into the token stream")
   421→	}
   422→
   423→	if typ != 0 && (typ <= startSymbolsStart || typ >= startSymbolsEnd) {
   424→		panic("cannot inject symbol that isn't start symbol")
   425→	}
   426→
   427→	p.inject = typ
   428→	p.injecting = true
   429→}
