   431→func (p *parser) newBinaryExpression(lhs Node, op Item, modifiers, rhs Node) *BinaryExpr {
   432→	ret := modifiers.(*BinaryExpr)
   433→
   434→	ret.LHS = lhs.(Expr)
   435→	ret.RHS = rhs.(Expr)
   436→	ret.Op = op.Typ
   437→
   438→	if !p.options.EnableBinopFillModifiers && (ret.VectorMatching.FillValues.LHS != nil || ret.VectorMatching.FillValues.RHS != nil) {
   439→		p.addParseErrf(ret.PositionRange(), "binop fill modifiers are experimental and not enabled")
   440→		return ret
   441→	}
   442→
   443→	return ret
   444→}
