   505→// mergeMaps is used to combine maps as they're used to later build the Float histogram.
   506→// This will merge the right map into the left map.
   507→func (p *parser) mergeMaps(left, right *map[string]any) (ret *map[string]any) {
   508→	for key, value := range *right {
   509→		if _, ok := (*left)[key]; ok {
   510→			p.addParseErrf(posrange.PositionRange{}, "duplicate key \"%s\" in histogram", key)
   511→			continue
   512→		}
   513→		(*left)[key] = value
   514→	}
   515→	return left
   516→}
