   668→func (p *parser) buildHistogramBucketsAndSpans(desc *map[string]any, bucketsKey, offsetKey string,
   669→) (buckets []float64, spans []histogram.Span) {
   670→	bucketCount := 0
   671→	val, ok := (*desc)[bucketsKey]
   672→	if ok {
   673→		val, ok := val.([]float64)
   674→		if ok {
   675→			buckets = val
   676→			bucketCount = len(buckets)
   677→		} else {
   678→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing %s float array: %v", bucketsKey, val)
   679→		}
   680→	}
   681→	offset := int32(0)
   682→	val, ok = (*desc)[offsetKey]
   683→	if ok {
   684→		val, ok := val.(int64)
   685→		if ok {
   686→			offset = int32(val)
   687→		} else {
   688→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing %s number: %v", offsetKey, val)
   689→		}
   690→	}
   691→	if bucketCount > 0 {
   692→		spans = []histogram.Span{{Offset: offset, Length: uint32(bucketCount)}}
   693→	}
   694→	return buckets, spans
   695→}
