   960→func (p *parser) newLabelMatcher(label, operator, value Item) *labels.Matcher {
   961→	op := operator.Typ
   962→	val := p.unquoteString(value.Val)
   963→
   964→	// Map the Item to the respective match type.
   965→	var matchType labels.MatchType
   966→	switch op {
   967→	case EQL:
   968→		matchType = labels.MatchEqual
   969→	case NEQ:
   970→		matchType = labels.MatchNotEqual
   971→	case EQL_REGEX:
   972→		matchType = labels.MatchRegexp
   973→	case NEQ_REGEX:
   974→		matchType = labels.MatchNotRegexp
   975→	default:
   976→		// This should never happen, since the error should have been caught
   977→		// by the generated parser.
   978→		panic("invalid operator")
   979→	}
   980→
   981→	m, err := labels.NewMatcher(matchType, label.Val, val)
   982→	if err != nil {
   983→		p.addParseErr(mergeRanges(&label, &value), err)
   984→	}
   985→
   986→	return m
   987→}
